judgeConfig.referenceSolution:
const toggleBtn = document.getElementById('toggle-modal');
const closeBtn = document.getElementById('close-modal');
const container = document.getElementById('modal-container');
const bg = document.getElementById('modal-bg');
const box = document.getElementById('modal-box');

let isOpen = false;
function toggle() {
  isOpen = !isOpen;
  if (isOpen) {
    container.classList.remove('pointer-events-none');
    bg.classList.add('opacity-100');
    box.classList.remove('opacity-0', 'scale-90', 'translate-y-4');
    box.classList.add('opacity-100', 'scale-100', 'translate-y-0');
  } else {
    container.classList.add('pointer-events-none');
    bg.classList.remove('opacity-100');
    box.classList.add('opacity-0', 'scale-90', 'translate-y-4');
    box.classList.remove('opacity-100', 'scale-100', 'translate-y-0');
  }
}
toggleBtn.addEventListener('click', toggle);
closeBtn.addEventListener('click', toggle);
